const input = $input.first();
const json = input.json || {};
const binary = input.binary || {};

const imageKey = [
  '产品图', 'Product Image', 'Product_Image', 'Image', 'image', 'product_image'
].find((k) => Object.prototype.hasOwnProperty.call(binary, k)) || Object.keys(binary)[0];

if (!imageKey) {
  throw new Error('未找到产品图。请在表单字段“产品图”上传1张图片。');
}

const apiKey = json['Gemini API Key'] || json['Gemini_API_Key'] || json['api_key'] || json['gemini_api_key'];
if (!apiKey) {
  throw new Error('Gemini API Key 不能为空。');
}

const fixedPrompt = json['固定提示词（原文）'] || json['固定提示词'] || json['Fixed Prompt'] || json['fixed_prompt'];
if (!fixedPrompt) {
  throw new Error('固定提示词不能为空。请粘贴你的固定提示词原文。');
}

const keywords = json['亚马逊关键词'] || json['Amazon Keywords'] || json['keywords'] || '';
if (!String(keywords).trim()) {
  throw new Error('亚马逊关键词不能为空。');
}

const maxRetryRaw = Number(json['最大重试次数'] ?? json['Max Retry'] ?? 5);
const maxRetry = Number.isFinite(maxRetryRaw) ? Math.max(1, Math.min(12, Math.floor(maxRetryRaw))) : 5;

const retryWaitSecondsRaw = Number(json['重试等待秒数'] ?? json['Retry Wait Seconds'] ?? 10);
const retryWaitMs = (Number.isFinite(retryWaitSecondsRaw) ? Math.max(1, Math.min(180, retryWaitSecondsRaw)) : 10) * 1000;

const gapSecondsRaw = Number(json['任务间隔秒数'] ?? json['Request Gap Seconds'] ?? 2);
const gapMs = (Number.isFinite(gapSecondsRaw) ? Math.max(0, Math.min(60, gapSecondsRaw)) : 2) * 1000;

const temperatureRaw = Number(json['温度'] ?? json['Temperature'] ?? 0.7);
const temperature = Number.isFinite(temperatureRaw) ? Math.max(0, Math.min(1.2, temperatureRaw)) : 0.7;

const filePrefixRaw = (json['文件名前缀'] || json['Output Prefix'] || 'amazon_jp').toString().trim();
const filePrefix = filePrefixRaw.replace(/[^a-zA-Z0-9_-]/g, '_') || 'amazon_jp';

const sourceBinary = binary[imageKey];
const sourceBuffer = await this.helpers.getBinaryDataBuffer(0, imageKey);
const sourceMimeType = sourceBinary.mimeType || 'image/png';
const sourceImageBase64 = Buffer.from(sourceBuffer).toString('base64');

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

const proUrl = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent';
const imageUrl = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image-preview:generateContent';

async function geminiCall(url, body) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: {
      'Content-Type': 'application/json',
      'x-goog-api-key': apiKey,
    },
    body,
    json: true,
    timeout: 300000,
  });
}

function extractText(resp) {
  const candidates = Array.isArray(resp?.candidates) ? resp.candidates : [];
  for (const candidate of candidates) {
    const parts = Array.isArray(candidate?.content?.parts) ? candidate.content.parts : [];
    for (const part of parts) {
      if (typeof part?.text === 'string' && part.text.trim()) {
        return part.text.trim();
      }
    }
  }
  return '';
}

function extractImageParts(resp) {
  const images = [];
  const candidates = Array.isArray(resp?.candidates) ? resp.candidates : [];

  for (const candidate of candidates) {
    const parts = Array.isArray(candidate?.content?.parts) ? candidate.content.parts : [];
    for (const part of parts) {
      const inline = part?.inlineData || part?.inline_data;
      if (inline?.data) {
        images.push({
          data: inline.data,
          mimeType: inline.mimeType || inline.mime_type || 'image/png',
        });
      }
      if (part?.image?.imageBytes) {
        images.push({
          data: part.image.imageBytes,
          mimeType: part.image.mimeType || 'image/png',
        });
      }
    }
  }
  return images;
}

function detectImageDimensions(base64, mimeTypeHint = '') {
  try {
    const b = Buffer.from(base64, 'base64');
    const hint = (mimeTypeHint || '').toLowerCase();

    // PNG
    if (
      b.length >= 24 &&
      b[0] === 0x89 && b[1] === 0x50 && b[2] === 0x4e && b[3] === 0x47 &&
      b[4] === 0x0d && b[5] === 0x0a && b[6] === 0x1a && b[7] === 0x0a
    ) {
      return {
        format: 'png',
        width: b.readUInt32BE(16),
        height: b.readUInt32BE(20),
      };
    }

    // JPEG
    if ((hint.includes('jpeg') || hint.includes('jpg') || (b[0] === 0xff && b[1] === 0xd8)) && b.length > 4) {
      let i = 2;
      while (i < b.length) {
        if (b[i] !== 0xff) { i++; continue; }
        const marker = b[i + 1];
        if (!marker || marker === 0xda || marker === 0xd9) break;
        const len = b.readUInt16BE(i + 2);
        if ([0xc0,0xc1,0xc2,0xc3,0xc5,0xc6,0xc7,0xc9,0xca,0xcb,0xcd,0xce,0xcf].includes(marker)) {
          return {
            format: 'jpeg',
            height: b.readUInt16BE(i + 5),
            width: b.readUInt16BE(i + 7),
          };
        }
        i += 2 + len;
      }
    }

    // WEBP
    if (b.length >= 30 && b.toString('ascii', 0, 4) === 'RIFF' && b.toString('ascii', 8, 12) === 'WEBP') {
      const chunk = b.toString('ascii', 12, 16);
      if (chunk === 'VP8X' && b.length >= 30) {
        const w = 1 + b.readUIntLE(24, 3);
        const h = 1 + b.readUIntLE(27, 3);
        return { format: 'webp', width: w, height: h };
      }
    }
  } catch (e) {
    return { format: 'unknown', width: null, height: null, error: e.message };
  }
  return { format: 'unknown', width: null, height: null };
}

const tasks = [
  { phase: 'main', order: 1, width: 1600, height: 1600, prompt: '主图1：白底纯产品图。背景必须纯白（#FFFFFF），只能有产品本体，不允许人物、动物、宠物、文字、水印、道具。' },
  { phase: 'main', order: 2, width: 1600, height: 1600, prompt: '主图2：日式家居场景卖点图，允许1位人物互动。产品结构、颜色、细节保持不变。' },
  { phase: 'main', order: 3, width: 1600, height: 1600, prompt: '主图3：宠物家庭场景图，可包含宠物（如狗/猫）。产品本体保持不变。' },
  { phase: 'main', order: 4, width: 1600, height: 1600, prompt: '主图4：出行/拉杆使用场景，强调拉杆与移动性。产品本体保持不变。' },
  { phase: 'main', order: 5, width: 1600, height: 1600, prompt: '主图5：功能卖点图，突出万向轮、拉杆、折叠结构。产品本体保持不变。' },
  { phase: 'main', order: 6, width: 1600, height: 1600, prompt: '主图6：容量与收纳组织场景图。产品本体保持不变。' },
  { phase: 'main', order: 7, width: 1600, height: 1600, prompt: '主图7：温暖生活化场景（人物+宠物可选）。产品本体保持不变。' },
  { phase: 'a_plus', order: 8, width: 970, height: 600, prompt: 'A+图1（970x600）：品牌横幅风格，必须与主图构图不同。产品本体保持不变。' },
  { phase: 'a_plus', order: 9, width: 970, height: 600, prompt: 'A+图2（970x600）：功能对比/优势说明视觉，必须与主图不同。产品本体保持不变。' },
  { phase: 'a_plus', order: 10, width: 970, height: 600, prompt: 'A+图3（970x600）：折叠步骤叙事型视觉，必须与主图不同。产品本体保持不变。' },
  { phase: 'a_plus', order: 11, width: 970, height: 600, prompt: 'A+图4（970x600）：材质与移动性叙事视觉，必须与主图不同。产品本体保持不变。' },
];

const globalRules = [
  '你的任务是基于用户提供的产品图进行电商视觉生成。',
  '严禁改变产品本体：外观结构、主要颜色、比例、拉杆与轮组形态必须保持一致。',
  '目标站点为日本亚马逊，风格需符合日本电商审美。',
  '每次只输出当前任务的一张图片。',
  '图片必须清晰，达到高分辨率质感。',
].join('\n');

let readyReply = '';
let readyStepStatus = 'failed';
let readyError = '';

const readyMaxRetry = Math.min(3, maxRetry);
for (let i = 1; i <= readyMaxRetry; i++) {
  try {
    const readyResp = await geminiCall(proUrl, {
      contents: [
        {
          role: 'user',
          parts: [
            { text: fixedPrompt },
          ],
        },
      ],
      generationConfig: {
        temperature: 0.2,
        maxOutputTokens: 256,
      },
    });

    readyReply = extractText(readyResp) || 'READY_REPLY_EMPTY';
    readyStepStatus = 'ok';
    readyError = '';
    break;
  } catch (err) {
    readyError = err.message;
    if (i < readyMaxRetry) {
      await sleep(retryWaitMs);
    }
  }
}

if (readyStepStatus !== 'ok') {
  throw new Error(`准备阶段失败（gemini-2.5-pro）。错误: ${readyError || 'unknown'}`);
}

const outputItems = [];
const failedTasks = [];
let generatedCount = 0;

for (const task of tasks) {
  let success = false;
  let lastError = '';

  for (let attempt = 1; attempt <= maxRetry; attempt++) {
    const retryHint = attempt === 1
      ? ''
      : `上次生成未得到合格图片，请重试当前任务。当前重试 ${attempt}/${maxRetry}。`;

    const promptText = [
      fixedPrompt,
      '',
      `亚马逊关键词: ${keywords}`,
      `当前阶段: ${task.phase}`,
      `当前序号: ${task.order}`,
      `目标尺寸: ${task.width}x${task.height}`,
      globalRules,
      `当前任务: ${task.prompt}`,
      retryHint,
    ].filter(Boolean).join('\n');

    let resp;
    try {
      resp = await geminiCall(imageUrl, {
        contents: [
          {
            role: 'user',
            parts: [
              { text: promptText },
              {
                inline_data: {
                  mime_type: sourceMimeType,
                  data: sourceImageBase64,
                },
              },
            ],
          },
        ],
        generationConfig: {
          temperature,
        },
      });
    } catch (err) {
      lastError = `HTTP_ERROR: ${err.message}`;
      if (attempt < maxRetry) await sleep(retryWaitMs);
      continue;
    }

    const images = extractImageParts(resp);
    if (!images.length) {
      lastError = extractText(resp) || 'NO_IMAGE_RETURNED';
      if (attempt < maxRetry) await sleep(retryWaitMs);
      continue;
    }

    const picked = images[0];
    const dim = detectImageDimensions(picked.data, picked.mimeType);
    const sizeOk = dim.width === task.width && dim.height === task.height;

    if (!sizeOk) {
      lastError = `SIZE_MISMATCH: got ${dim.width || '?'}x${dim.height || '?'}, expected ${task.width}x${task.height}`;
      if (attempt < maxRetry) await sleep(retryWaitMs);
      continue;
    }

    const ext = (() => {
  const m = (picked.mimeType || 'image/png').toLowerCase();
  if (m.includes('jpeg') || m.includes('jpg')) return 'jpg';
  if (m.includes('webp')) return 'webp';
  if (m.includes('png')) return 'png';
  return 'png';
})();
const fileName = `${filePrefix}_${task.phase}_${String(task.order).padStart(2, '0')}_${task.width}x${task.height}.${ext}`;

    outputItems.push({
      json: {
        status: 'ok',
        phase: task.phase,
        task_order: task.order,
        target_size: `${task.width}x${task.height}`,
        actual_size: `${dim.width}x${dim.height}`,
        attempt_used: attempt,
        extra_images_in_same_response: Math.max(0, images.length - 1),
        ready_step_status: readyStepStatus,
        ready_reply: readyReply,
        prompt_used: task.prompt,
        source_image_field: imageKey,
        source_image_mime: sourceMimeType,
        model: 'gemini-2.5-flash-image-preview',
      },
      binary: {
        image: {
          data: picked.data,
          mimeType: picked.mimeType || 'image/png',
          fileName,
        },
      },
    });

    generatedCount += 1;
    success = true;
    break;
  }

  if (!success) {
    failedTasks.push({
      phase: task.phase,
      task_order: task.order,
      target_size: `${task.width}x${task.height}`,
      prompt: task.prompt,
      error: lastError,
    });
  }

  if (gapMs > 0) {
    await sleep(gapMs);
  }
}

outputItems.push({
  json: {
    status: failedTasks.length ? 'partial' : 'success',
    generated_count: generatedCount,
    expected_count: tasks.length,
    failed_count: failedTasks.length,
    failed_tasks: failedTasks,
    ready_step_status: readyStepStatus,
    ready_reply: readyReply,
    retry_config: {
      max_retry: maxRetry,
      retry_wait_seconds: retryWaitMs / 1000,
      task_gap_seconds: gapMs / 1000,
      temperature,
    },
    note: failedTasks.length
      ? '存在失败任务。可提高最大重试次数后重跑。'
      : '11张图片全部成功生成。',
  },
});

return outputItems;
